import uvicorn
from fastapi import FastAPI, Depends, HTTPException, status, Request
from fastapi.security import OAuth2AuthorizationCodeBearer
from typing import Optional
import redis.asyncio as redis
from pydantic import BaseModel

# Configuration
REDIS_HOST = "localhost"
REDIS_PORT = 6379
REDIS_DB = 0
TOKEN_PREFIX = "valid_token:" # Prefix for keys in Redis for valid tokens

# Initialize FastAPI app
app = FastAPI()

# OAuth2 scheme (not used for actual token validation in this example, but good for OpenAPI docs)
# We are manually extracting the bearer token from the header for custom validation.
oauth2_scheme = OAuth2AuthorizationCodeBearer(authorizationUrl="/oauth2/authorize", tokenUrl="/oauth2/token")

# Pydantic model for a simple response
class MessageResponse(BaseModel):
    message: str

# Dependency for Redis client
async def get_redis_client():
    """
    Returns an asynchronous Redis client.
    Handles connection and closing.
    """
    client = redis.Redis(host=REDIS_HOST, port=REDIS_PORT, db=REDIS_DB)
    try:
        yield client
    finally:
        await client.close()

# Dependency for token validation
async def validate_bearer_token(
    request: Request,
    redis_client: redis.Redis = Depends(get_redis_client)
) -> str:
    """
    Extracts the bearer token from the Authorization header and validates it against Redis.
    Raises HTTPException if the token is missing or invalid.
    """
    auth_header = request.headers.get("Authorization")
    if not auth_header:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Authorization header missing",
            headers={"WWW-Authenticate": "Bearer"},
        )

    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != "bearer":
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid Authorization header format. Expected 'Bearer <token>'",
            headers={"WWW-Authenticate": "Bearer"},
        )

    token = parts[1]
    
    # Check if the token exists in Redis
    # In a real-world scenario, you might store user info or expiration time here
    # For this example, we just check for existence of the token prefixed key.
    is_valid = await redis_client.exists(f"{TOKEN_PREFIX}{token}")

    if not is_valid:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    return token

