@app.post("/logout", response_model=MessageResponse)
async def logout(
    request: Request,
    redis_client: redis.Redis = Depends(get_redis_client)
):
    """
    Simulates a logout endpoint that invalidates a token from Redis.
    """
    auth_header = request.headers.get("Authorization")
    if not auth_header:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Authorization header missing for logout",
        )

    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != "bearer":
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Invalid Authorization header format.",
        )

    token_to_invalidate = parts[1]
    
    # Remove the token from Redis
    deleted_count = await redis_client.delete(f"{TOKEN_PREFIX}{token_to_invalidate}")

    if deleted_count == 0:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail="Token not found or already invalidated.",
        )

    return {"message": "Token successfully invalidated (logged out)."}

